const allItems = $input.all();
const allContacts = [];
const seen = new Set();
for (const item of allItems) {
  const contacts = item.json.contacts || [];
  for (const c of contacts) {
    if (!seen.has(c.id)) {
      seen.add(c.id);
      allContacts.push({ id: c.id, firstName: c.firstName || '', lastName: c.lastName || '', email: c.email || '', phone: c.phone || '', tags: c.tags || [] });
    }
  }
}
return allContacts.map(c => ({ json: c }));

const convItems = $input.all();
const contactItems = $('Loop Contacts').all();
const results = [];
for (let i = 0; i < convItems.length; i++) {
  const contact = contactItems[i].json;
  const conversations = convItems[i].json.conversations || [];
  if (conversations.length > 0) {
    results.push({
      json: {
        contactId: contact.id,
        contactName: (contact.firstName + ' ' + contact.lastName).trim(),
        contactEmail: contact.email || '',
        contactTags: contact.tags || [],
        conversationId: conversations[0].id
      }
    });
  }
}
if (results.length === 0) {
  results.push({ json: { contactId: '', contactName: 'none', contactEmail: '', contactTags: [], conversationId: '' } });
}
return results;

const msgItems = $input.all();
const convItems = $('Process Conversations').all();
const results = [];
for (let i = 0; i < msgItems.length; i++) {
  const contact = convItems[i].json;
  const raw = msgItems[i].json;
  if (!raw || !raw.messages) continue;
  const msgArray = raw.messages.messages || [];
  const messages = msgArray
    .filter(m => m && ['TYPE_SMS', 'TYPE_EMAIL'].includes(m.messageType) && m.body)
    .sort((a, b) => new Date(a.dateAdded) - new Date(b.dateAdded));
  if (messages.length === 0) continue;
  let transcript = 'Contact: ' + contact.contactName + ' (' + contact.contactEmail + ')\nTags: ' + contact.contactTags.join(', ') + '\n\n--- CONVERSATION ---\n\n';
  for (const msg of messages) {
    const speaker = msg.direction === 'inbound' ? '[CUSTOMER - ' + contact.contactName + ']' : '[GM BAPTIST TEAM]';
    const body = msg.body.length > 500 ? msg.body.substring(0, 500) + '...' : msg.body;
    const msgType = msg.messageType === 'TYPE_SMS' ? 'SMS' : 'Email';
    transcript += speaker + ' (' + msgType + ', ' + msg.dateAdded + '):\n' + body + '\n\n';
  }
  if (transcript.length > 8000) transcript = transcript.substring(0, 8000) + '\n\n[TRUNCATED]';
  results.push({ json: { contactName: contact.contactName, contactTags: contact.contactTags, transcript: transcript } });
}
if (results.length === 0) {
  results.push({ json: { contactName: 'none', contactTags: [], transcript: '' } });
}
return results;

const items = $input.all();
return items.map(item => {
  const prompt = 'You are analyzing customer support conversations for GM Baptist Outreach, a church SaaS platform. Extract QUESTIONS the customer asked and ANSWERS given by the team.\n\nRules:\n- Only extract genuine questions from the CUSTOMER (inbound messages)\n- Skip greetings, thank yous, confirmations\n- For each question include the team answer if given\n- If no real questions return {"questions": []}\n\nReturn ONLY valid JSON:\n{"questions": [{"question": "...", "answer": "...", "topic": "..."}]}\n\nTranscript:\n\n' + item.json.transcript;
  return {
    json: {
      contactName: item.json.contactName,
      contactTags: item.json.contactTags,
      requestBody: {
        model: 'claude-sonnet-4-20250514',
        max_tokens: 2000,
        messages: [{ role: 'user', content: prompt }]
      }
    }
  };
});

const claudeItems = $input.all();
const prepItems = $('Prepare Q&A Request').all();
const results = [];
for (let i = 0; i < claudeItems.length; i++) {
  const contact = prepItems[i].json;
  let qaData = { questions: [] };
  try {
    const text = claudeItems[i].json.content[0].text;
    const match = text.match(/\{[\s\S]*\}/);
    if (match) qaData = JSON.parse(match[0]);
  } catch (e) {}
  results.push({ json: { contactName: contact.contactName, contactTags: contact.contactTags, questions: qaData.questions || [] } });
}
return results;

// Store Q&As in workflow static data across loop iterations
const staticData = $getWorkflowStaticData('global');
if (!staticData.allQuestions) staticData.allQuestions = [];
const items = $input.all();
for (const item of items) {
  for (const q of (item.json.questions || [])) {
    staticData.allQuestions.push({ question: q.question, answer: q.answer, topic: q.topic, contactName: item.json.contactName, contactTags: item.json.contactTags });
  }
}
return [{ json: { stored: true, totalSoFar: staticData.allQuestions.length } }];

// Collect all stored Q&As after loop completes
const staticData = $getWorkflowStaticData('global');
const allQuestions = staticData.allQuestions || [];
// Clear for next run
staticData.allQuestions = [];
return [{ json: { totalQuestions: allQuestions.length, questions: allQuestions } }];

const data = $input.first().json;
if (data.totalQuestions === 0) {
  return [{ json: { totalQuestions: 0, requestBody: { model: 'claude-sonnet-4-20250514', max_tokens: 1000, messages: [{ role: 'user', content: 'No questions were found. Return: {"faq_categories": [], "support_gaps": [], "summary": {"total_unique_questions": 0, "top_3_topics": [], "insight": "No questions found"}}' }] } } }];
}
const questionsStr = JSON.stringify(data.questions).substring(0, 12000);
const prompt = 'You are a business analyst for GM Baptist Outreach, a church SaaS platform that provides Facebook ad campaigns, automated texting, websites, and software tools for Baptist churches.

Below are questions from real customer conversations. Your job:
1. GROUP similar questions (deduplicate)
2. CATEGORIZE into FAQ sections
3. RANK by frequency (most common first)
4. Write CLEAR FAQ answers
5. Flag UNANSWERED questions as support gaps

Return JSON:
{"faq_categories": [{"category": "...", "questions": [{"question": "...", "answer": "...", "frequency": 1, "source_contacts": []}]}], "support_gaps": [{"question": "...", "recommendation": "..."}], "summary": {"total_unique_questions": 0, "top_3_topics": [], "insight": "..."}}

Q&A pairs:
' + questionsStr;
return [{ json: { totalQuestions: data.totalQuestions, requestBody: { model: 'claude-sonnet-4-20250514', max_tokens: 4000, messages: [{ role: 'user', content: prompt }] } } }];

const item = $input.first().json;
const aggregate = $('Aggregate Q&As').first().json;
let faqData = {};
try {
  const text = item.content[0].text;
  const match = text.match(/\{[\s\S]*\}/);
  if (match) faqData = JSON.parse(match[0]);
} catch (e) {
  faqData = { error: 'Failed to parse', raw: item.content && item.content[0] ? item.content[0].text : '' };
}
return [{ json: { generatedAt: new Date().toISOString(), totalContactsAnalyzed: $('Deduplicate Contacts').all().length, totalQuestionsExtracted: aggregate.totalQuestions, ...faqData } }];
